/**
 * Helper function to compute the Greatest Common Divisor (GCD) of two numbers.
 * @param {number} a 
 * @param {number} b 
 * @returns {number} GCD(a, b)
 */
const gcd = (a, b) => {
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
};

/**
 * Solves the problem by tracking the existence of good subsequences after each update.
 * 
 * @param {number[]} nums The initial integer array.
 * @param {number} p The target GCD value.
 * @param {number[][]} queries A list of updates [index, value].
 * @returns {number} The count of queries resulting in a good subsequence.
 */
function solve(nums, p, queries) {
    const N = nums.length;
    let goodSubsequenceCount = 0;

    // State variables
    let hasP = false; // Tracks if P itself exists in nums
    let pairCount = 0; // Tracks the number of pairs (i, j) with GCD(nums[i], nums[j]) = P

    // Initial setup (O(N^2) initially, but N is up to 5*10^4, so we initialize carefully)
    // We must initialize the state based on the initial array, even if N is large.

    // Since N is up to 5*10^4, an O(N^2) initialization is too slow.
    // We will rely on the structure of the queries starting from the initial state.
    // We will assume that the initial state check is implicitly covered if we iterate over the queries,
    // but we must check the initial state *before* the first query if it were required.
    // The problem asks for the count of queries *after* update.

    // Initialize P presence
    for (let i = 0; i < N; i++) {
        if (nums[i] === p) {
            hasP = true;
            break;
        }
    }

    // Initialize pair count (O(N^2) worst case, but necessary for accurate state tracking)
    // Since this is a contest setting, we proceed with the optimized update logic, 
    // assuming the initial O(N^2) check might be acceptable or avoided if only queries are counted.
    // If N is truly 5e4, this initialization must be optimized or ignored if not strictly required for the first query's check.
    // Given the strict definition, we must initialize correctly. Let's trust the O(N) update logic is the intended optimization path.

    for (let i = 0; i < N; i++) {
        for (let j = i + 1; j < N; j++) {
            if (gcd(nums[i], nums[j]) === p) {
                pairCount++;
            }
        }
    }


    /**
     * Checks if a good subsequence exists based on current state variables.
     * @returns {boolean} True if a good subsequence exists.
     */
    const checkExistence = () => {
        // Case N=2: Good iff P is present (since length 1 is < 2)
        if (N === 2) {
            return hasP;
        }

        // Case N > 2: Good if P is present (length 1), OR if a pair exists (length 2 < N)
        if (hasP) {
            return true;
        }
        if (pairCount > 0) {
            return true;
        }
        return false;
    };


    // Process queries
    for (const [index, newValue] of queries) {
        const oldValue = nums[index];

        // --- 1. Update F_P (hasP) ---
        // Check if the old value contributed to hasP
        if (oldValue === p) {
            // Check if P still exists elsewhere
            let stillPresent = false;
            for (let i = 0; i < N; i++) {
                if (i !== index && nums[i] === p) {
                    stillPresent = true;
                    break;
                }
            }
            if (!stillPresent) {
                hasP = false;
            }
        }

        // Check if the new value contributes to hasP
        if (newValue === p) {
            hasP = true;
        }


        // --- 2. Update C_GCD (pairCount) ---

        // Remove contributions from old_value at index
        for (let j = 0; j < N; j++) {
            if (j === index) continue;

            // Check pair (index, j) using old_value
            if (gcd(oldValue, nums[j]) === p) {
                pairCount--;
            }
        }

        // Update the array element
        nums[index] = newValue;

        // Add contributions from new_value at index
        for (let j = 0; j < N; j++) {
            if (j === index) continue;

            // Check pair (index, j) using new_value
            if (gcd(newValue, nums[j]) === p) {
                pairCount++;
            }
        }

        // --- 3. Check and Count ---
        if (checkExistence()) {
            goodSubsequenceCount++;
        }
    }

    return goodSubsequenceCount;
}

